-- ============================================================================
-- 034_degree_college_seed_01.sql  -  AP degree colleges (OAMDC / APSCHE)
-- GENERATED by gen_seed_034.py from college_data.csv (scraper.py output).
-- 1258 colleges + 26 affiliating universities.
--
-- Idempotent + re-runnable: widens the ownership_type CHECK, clears prior
-- OAMDC rows (college_code is not null) WITHOUT touching universities or the
-- legacy 008 rows (both null code), re-seeds every referenced university as a
-- self-referential row (university_id = id), then inserts each college with
-- university_id resolved by name. Universities not in the 033 seed carry
-- best-effort place/district/year; only name + ownership_type are authoritative.
-- ============================================================================

alter table public.college drop constraint if exists college_ownership_type_check;
alter table public.college add constraint college_ownership_type_check
  check (ownership_type in (
    'GOVERNMENT', 'PRIVATE',            -- legacy values (008_*)
    'PRIVATE_UNAIDED', 'PRIVATE_AIDED', 'PRIVATE_UNIVERSITY', 'UNIVERSITY_COLLEGE'
  ));

-- Clear only OAMDC-coded colleges (re-runnable); universities + 008 rows have
-- a null college_code and are left untouched.
delete from public.college where college_code is not null;

-- Seed/repair affiliating universities (self-referential rows). where-not-exists
-- keeps it idempotent; the update self-associates any not yet pointing at itself.
